        const scrollAmount = slider.clientWidth * 0.80; 

        slider.style.scrollSnapType = 'x mandatory';
        slider.style.scrollBehavior = 'smooth';

        slider.scrollBy({
            left: direction === 'left' ? -scrollAmount : scrollAmount,
            behavior: 'smooth'
        });
    };

    return (
